import{f as a,o as d,c as e,a2 as r}from"./chunks/framework.Ccw_j35p.js";const u=JSON.parse('{"title":"高并发架构","description":"","frontmatter":{},"headers":[],"relativePath":"high-concurrency/index.md","filePath":"high-concurrency/index.md","lastUpdated":1780734044000}'),l={name:"high-concurrency/index.md"};function i(o,t,s,h,n,c){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="高并发架构" tabindex="-1">高并发架构 <a class="header-anchor" href="#高并发架构" aria-label="Permalink to &quot;高并发架构&quot;">​</a></h1><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>高并发架构是高级工程师面试中的&quot;决胜题&quot;，考察候选人对系统整体设计、瓶颈分析和方案选型的综合能力。本模块覆盖分层架构、扩展策略、高可用设计、分布式核心理论和经典场景方案，帮助你建立完整的系统设计思维框架。</p><div class="tip custom-block"><p class="custom-block-title">核心思路</p><p>高并发不是单一技术的堆砌，而是<strong>分层架构设计</strong> + <strong>各层独立扩展</strong> + <strong>瓶颈精准识别</strong>的系统工程。</p></div><div class="info custom-block"><p class="custom-block-title">设计原则</p><p>先做垂直扩展探顶，再做水平扩展；先读写分离，再分库分表；先缓存加速，再异步解耦。</p></div><h2 id="核心知识点" tabindex="-1">核心知识点 <a class="header-anchor" href="#核心知识点" aria-label="Permalink to &quot;核心知识点&quot;">​</a></h2><h3 id="架构分层与扩展" tabindex="-1">架构分层与扩展 <a class="header-anchor" href="#架构分层与扩展" aria-label="Permalink to &quot;架构分层与扩展&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>分层架构</td><td>客户端层 → CDN → 反向代理层（Nginx） → 网关层 → 业务层 → 数据层</td></tr><tr><td>垂直扩展</td><td>升级 CPU / 内存 / 磁盘，SSD 替换 HDD，瓶颈与极限</td></tr><tr><td>水平扩展</td><td>无状态服务弹性伸缩、有状态服务的数据分片、负载均衡策略</td></tr><tr><td>动静分离</td><td>静态资源 CDN + OSS、动态页面服务化</td></tr><tr><td>读写分离</td><td>主从复制延迟处理、强制读主、ShardingSphere 读写分离配置</td></tr></tbody></table><h3 id="缓存架构" tabindex="-1">缓存架构 <a class="header-anchor" href="#缓存架构" aria-label="Permalink to &quot;缓存架构&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>多级缓存</td><td>浏览器缓存 → CDN 缓存 → Nginx 本地缓存 → Redis 分布式缓存 → 本地缓存（Caffeine）</td></tr><tr><td>缓存预热</td><td>冷启动问题、定时任务预热、流量回放预热</td></tr><tr><td>缓存更新</td><td>Cache Aside / Read Through / Write Through / Write Behind 模式对比</td></tr><tr><td>热点处理</td><td>热点 Key 发现（客户端采集 + 上报）、多级拆分（本地 + 分布式）、多副本</td></tr></tbody></table><h3 id="异步与削峰" tabindex="-1">异步与削峰 <a class="header-anchor" href="#异步与削峰" aria-label="Permalink to &quot;异步与削峰&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>消息队列削峰</td><td>瞬时流量 → MQ → 平滑消费，消费速度控制</td></tr><tr><td>请求合并</td><td>高频小请求合并为批量处理（Hystrix Request Collapsing）</td></tr><tr><td>异步处理</td><td>CompletableFuture 编排、MQ 异步解耦、响应式编程（Reactor/WebFlux）</td></tr></tbody></table><h3 id="高可用设计" tabindex="-1">高可用设计 <a class="header-anchor" href="#高可用设计" aria-label="Permalink to &quot;高可用设计&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>冗余与容灾</td><td>同城双活、两地三中心、多活架构的挑战（数据同步/路由）</td></tr><tr><td>限流</td><td>计数器/滑动窗口/漏桶/令牌桶算法对比、Nginx 限流、Sentinel 控制台</td></tr><tr><td>降级</td><td>降级策略（返回默认值/缓存/兜底页面）、自动降级 vs 手动降级</td></tr><tr><td>熔断</td><td>熔断器状态机（Closed → Open → Half-Open）、慢调用比例 vs 异常比例</td></tr><tr><td>隔离</td><td>线程池隔离（Bulkhead）、信号量隔离、舱壁模式</td></tr></tbody></table><h3 id="分布式理论" tabindex="-1">分布式理论 <a class="header-anchor" href="#分布式理论" aria-label="Permalink to &quot;分布式理论&quot;">​</a></h3><table tabindex="0"><thead><tr><th>子模块</th><th>核心内容</th></tr></thead><tbody><tr><td>CAP 定理</td><td>一致性、可用性、分区容错三者取舍，不同中间件的 CAP 选择</td></tr><tr><td>BASE 理论</td><td>基本可用、软状态、最终一致性，AP 系统的设计哲学</td></tr><tr><td>一致性协议</td><td>2PC/3PC（XA 事务）、TCC（Try-Confirm-Cancel）、Paxos/Raft（共识算法）</td></tr><tr><td>分布式 ID</td><td>雪花算法（Snowflake）详解、号段模式（Leaf）、Redis 自增</td></tr><tr><td>分布式锁</td><td>Redis（SET NX + Lua / RedLock / Redisson）、Zookeeper（临时顺序节点）、Etcd</td></tr></tbody></table><h3 id="场景设计" tabindex="-1">场景设计 <a class="header-anchor" href="#场景设计" aria-label="Permalink to &quot;场景设计&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>核心方案</th></tr></thead><tbody><tr><td>秒杀系统</td><td>前端限流 → 网关校验 → 库存预热到 Redis → Lua 原子扣减 → MQ 异步下单</td></tr><tr><td>短链系统</td><td>发号器生成唯一 ID → Base62 编码 → 302 重定向 → 布隆过滤器防穿透</td></tr><tr><td>排行榜</td><td>Redis ZSet（实时榜单） + 定时任务归档到 MySQL（历史榜单）</td></tr><tr><td>消息推送</td><td>WebSocket 长连接 → 心跳保活 → 连接路由表 → MQ 广播</td></tr><tr><td>文件上传</td><td>分片上传 → 秒传（MD5 校验）→ OSS 直传 → CDN 加速</td></tr></tbody></table><h2 id="面试重点" tabindex="-1">面试重点 <a class="header-anchor" href="#面试重点" aria-label="Permalink to &quot;面试重点&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">高频考点</p><ol><li><strong>秒杀系统设计</strong>：从前端到后端到数据的完整链路，每层的瓶颈和解决方案</li><li><strong>CAP 理论应用</strong>：结合具体中间件说明取舍（Nacos AP / ZK CP / Eureka AP）</li><li><strong>分布式 ID</strong>：雪花算法时钟回拨问题怎么解决？Leaf 号段模式为什么比雪花更可靠？</li><li><strong>缓存一致性</strong>：先删缓存还是先更新数据库？延迟双删解决了什么？Canal 方案怎么玩？</li><li><strong>限流算法对比</strong>：漏桶 vs 令牌桶 vs 滑动窗口，各自适用场景</li><li><strong>分布式事务</strong>：2PC/3PC/TCC/Saga/可靠消息最终一致性，画图对比，选型标准</li><li><strong>系统容量估算</strong>：给定 DAU/QPS，估算服务器数量、带宽、存储容量</li></ol></div><div class="danger custom-block"><p class="custom-block-title">容易翻车的点</p><ul><li>直接将单机方案套用到分布式场景，忽视数据一致性问题</li><li>设计没有量化思维，不说具体数字（QPS、RT、容量）</li><li>方案停留在概念层，不能落地到具体技术和配置</li><li>只考虑功能，不考虑异常情况下的降级和容错</li></ul></div><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><h3 id="阶段一-理论奠基-2-周" tabindex="-1">阶段一：理论奠基（2 周） <a class="header-anchor" href="#阶段一-理论奠基-2-周" aria-label="Permalink to &quot;阶段一：理论奠基（2 周）&quot;">​</a></h3><ol><li>深入理解 CAP、BASE、一致性哈希、Quorum 等分布式核心理论</li><li>阅读 Raft 论文，理解分布式共识的核心思想</li><li>用纸笔画出 5 个经典场景的架构图（秒杀、短链、推送、IM、Feed 流）</li></ol><h3 id="阶段二-组件实战-3-周" tabindex="-1">阶段二：组件实战（3 周） <a class="header-anchor" href="#阶段二-组件实战-3-周" aria-label="Permalink to &quot;阶段二：组件实战（3 周）&quot;">​</a></h3><ol start="4"><li>搭建 Redis Cluster + Sentinel，模拟主从切换和脑裂</li><li>用 JMeter 压测 Nginx → Gateway → Sentinel → 业务服务的全链路</li><li>实现雪花算法，模拟时钟回拨问题并给出解决方案</li></ol><h3 id="阶段三-场景模拟-2-周" tabindex="-1">阶段三：场景模拟（2 周） <a class="header-anchor" href="#阶段三-场景模拟-2-周" aria-label="Permalink to &quot;阶段三：场景模拟（2 周）&quot;">​</a></h3><ol start="7"><li>完成秒杀系统的代码实现（限流 + 缓存预热 + Lua + MQ 异步下单）</li><li>设计并实现一个分布式锁压测，对比 Redis vs ZK vs Etcd 性能差异</li><li>编写系统设计文档模板，从需求 → 容量估算 → 架构图 → 数据流 → 异常处理全流程</li></ol><details class="details custom-block"><summary>推荐书单</summary><ul><li>《大型网站技术架构：核心原理与案例分析》—— 李智慧</li><li>《数据密集型应用系统设计》（DDIA）—— Martin Kleppmann</li><li>《亿级流量网站架构核心技术》—— 张开涛</li><li>《深入分布式缓存：从原理到实践》—— 于君泽</li><li>Google SRE 相关论文</li></ul></details>',29)])])}const m=a(l,[["render",i]]);export{u as __pageData,m as default};
